import{_ as a,o as s,c as t,a2 as n}from"./chunks/framework.LN3EJxkW.js";const u=JSON.parse('{"title":"Redis 数据类型、原子命令与内存模型","description":"","frontmatter":{"stage":"intermediate","direction":"backend-data","topic":"redis-data-types"},"headers":[],"relativePath":"05-backend-data/notes/07-cache-messaging-storage/01-redis-data-types.md","filePath":"05-backend-data/notes/07-cache-messaging-storage/01-redis-data-types.md","lastUpdated":null}'),i={name:"05-backend-data/notes/07-cache-messaging-storage/01-redis-data-types.md"};function r(l,e,d,p,o,c){return s(),t("div",null,[...e[0]||(e[0]=[n(`<h1 id="redis-数据类型、原子命令与内存模型" tabindex="-1">Redis 数据类型、原子命令与内存模型 <a class="header-anchor" href="#redis-数据类型、原子命令与内存模型" aria-label="Permalink to &quot;Redis 数据类型、原子命令与内存模型&quot;">​</a></h1><p>Redis 是以内存数据结构和命令为接口的数据服务。选择类型时要同时考虑访问模式、单键大小、原子边界、持久化、复制、Cluster 分片和故障后可接受的数据损失，而不是把所有对象序列化成 String。</p><h2 id="_1-能力边界与前置知识" tabindex="-1">1. 能力边界与前置知识 <a class="header-anchor" href="#_1-能力边界与前置知识" aria-label="Permalink to &quot;1. 能力边界与前置知识&quot;">​</a></h2><p>本文假定已经掌握哈希表、链表、集合、堆、数据库事务和缓存事实来源。Redis Open Source 8.8 包含传统核心类型，也集成了 JSON、概率结构、Time Series、Search 与 Vector Set 等能力；本文聚焦 roadmap 指定的 String、Hash、List、Set、Sorted Set、Bitmap、HyperLogLog、Stream 与 Geo。</p><p>Redis 命令通常在服务端事件循环中按命令原子执行。原子只表示其他命令不会观察到该命令的中间状态，不表示多个独立命令自动组成事务，也不表示主节点确认的写一定在故障转移后保留。</p><h2 id="_2-从访问模式选择类型" tabindex="-1">2. 从访问模式选择类型 <a class="header-anchor" href="#_2-从访问模式选择类型" aria-label="Permalink to &quot;2. 从访问模式选择类型&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart TD</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[&quot;数据要怎样读取&quot;] --&gt; B[&quot;按 key 取一个值&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A --&gt; C[&quot;按 field 局部更新&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A --&gt; D[&quot;按插入顺序取首尾&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A --&gt; E[&quot;成员去重与集合运算&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A --&gt; F[&quot;按 score 排序/范围&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A --&gt; G[&quot;按位记录布尔状态&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A --&gt; H[&quot;近似去重计数&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A --&gt; I[&quot;追加事件和消费组&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A --&gt; J[&quot;经纬度附近查询&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; K[&quot;String&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; L[&quot;Hash&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; M[&quot;List&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    E --&gt; N[&quot;Set&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    F --&gt; O[&quot;Sorted Set&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    G --&gt; P[&quot;Bitmap&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    H --&gt; Q[&quot;HyperLogLog&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    I --&gt; R[&quot;Stream&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    J --&gt; S[&quot;Geo&quot;]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br></div></div><p>一个业务对象可以由多个 key 表达，但多键操作在 Cluster 中受 hash slot 限制。高频更新集中在单个大 key 会形成热点；把数据拆成大量微小 key 又增加 key 元数据、网络往返和过期管理成本。</p><h2 id="_3-string-字节序列、计数器与条件写" tabindex="-1">3. String：字节序列、计数器与条件写 <a class="header-anchor" href="#_3-string-字节序列、计数器与条件写" aria-label="Permalink to &quot;3. String：字节序列、计数器与条件写&quot;">​</a></h2><p>String 保存二进制安全字节序列，值最大长度受 Redis 限制和部署内存约束。常用命令：</p><table tabindex="0"><thead><tr><th>命令</th><th>原子行为</th><th>典型用途</th><th>边界</th></tr></thead><tbody><tr><td><code>GET key</code></td><td>读完整值</td><td>缓存 JSON/二进制</td><td>大值产生网络和复制成本</td></tr><tr><td><code>SET key value NX PX ms</code></td><td>不存在才写并设置毫秒 TTL</td><td>抢占、初始化</td><td>锁还需唯一值与 fencing</td></tr><tr><td><code>MGET</code>/<code>MSET</code></td><td>批量读写</td><td>降低往返</td><td>Cluster 跨 slot 可能受限</td></tr><tr><td><code>INCRBY</code></td><td>整数解析并原子增加</td><td>计数、序列</td><td>溢出/业务上限需处理</td></tr><tr><td><code>GETEX</code></td><td>读取并修改过期</td><td>滑动会话</td><td>每读续期会保留冷数据</td></tr><tr><td><code>GETDEL</code></td><td>读取并删除</td><td>一次性 token</td><td>故障/重试后需明确语义</td></tr></tbody></table><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>SET session:7:Rk3... &#39;{&quot;user_id&quot;:&quot;u_9&quot;}&#39; EX 1800 NX</span></span>
<span class="line"><span>GET session:7:Rk3...</span></span>
<span class="line"><span>INCRBY quota:tenant:t_7:20260717 3</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>计数器的非负约束不能用 <code>GET</code> 后 <code>DECRBY</code> 两条命令保证；使用 Lua/Function 在服务端检查并修改，或让数据库承担资金、库存等最终不变量。</p><h2 id="_4-hash-同一对象的字段集合" tabindex="-1">4. Hash：同一对象的字段集合 <a class="header-anchor" href="#_4-hash-同一对象的字段集合" aria-label="Permalink to &quot;4. Hash：同一对象的字段集合&quot;">​</a></h2><p>Hash 把 field 映射到 value，适合局部读写扁平对象：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>HSET product:p_8 name &quot;Keyboard&quot; price_cents 69900 stock_hint 12</span></span>
<span class="line"><span>HGET product:p_8 price_cents</span></span>
<span class="line"><span>HMGET product:p_8 name price_cents</span></span>
<span class="line"><span>HINCRBY product:p_8 view_count 1</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>Hash field 不是独立 key。key 级 TTL 不会因删除一个 field 自动分离；Redis 8 系列还提供 hash field expiration 能力，但客户端、部署版本和命令兼容必须确认。需要所有字段一起失效时仍优先 key TTL。</p><p>Hash 适合几十到几百个字段的对象，不适合把整个租户百万用户塞进一个 hash：单 key 迁移、删除、持久化和热点风险集中。字段值依旧是字节序列，不会自动建立二级索引或类型约束。</p><h2 id="_5-list-有序序列和阻塞弹出" tabindex="-1">5. List：有序序列和阻塞弹出 <a class="header-anchor" href="#_5-list-有序序列和阻塞弹出" aria-label="Permalink to &quot;5. List：有序序列和阻塞弹出&quot;">​</a></h2><p>List 按插入顺序保存字符串，支持首尾 push/pop、范围和阻塞读取。<code>LPUSH</code> + <code>BRPOP</code> 可构造简单工作队列；<code>LMOVE</code>/<code>BLMOVE</code> 可先把任务移入 processing list 再处理，减少消费者取出后崩溃导致的直接丢失。</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>LPUSH queue:thumbnail job_103</span></span>
<span class="line"><span>BRPOPLPUSH queue:thumbnail queue:thumbnail:processing 5</span></span>
<span class="line"><span>LREM queue:thumbnail:processing 1 job_103</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>这仍不是完整消息系统：没有内建尝试次数、消费组、事件重放、schema、分区扩展和稳定审计。重入队列过程可能重复，消费者必须幂等。大量 <code>LRANGE 0 -1</code> 会返回整个大列表，应限制范围。</p><h2 id="_6-set-唯一成员与集合运算" tabindex="-1">6. Set：唯一成员与集合运算 <a class="header-anchor" href="#_6-set-唯一成员与集合运算" aria-label="Permalink to &quot;6. Set：唯一成员与集合运算&quot;">​</a></h2><p>Set 是无序唯一字符串集合。成员增删和存在判断适合标签、权限集合、去重标识：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>SADD user:u_9:roles editor auditor</span></span>
<span class="line"><span>SISMEMBER user:u_9:roles editor</span></span>
<span class="line"><span>SINTER project:p_2:members tenant:t_7:active_users</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p><code>SINTER</code>、<code>SUNION</code>、<code>SDIFF</code> 的成本与参与集合大小有关，不能在请求路径对百万级集合无界运算。<code>SSCAN</code> 是增量遍历，不保证一次迭代期间无重复，也不能提供事务快照；调用方去重并容忍并发变化。</p><p>Set 成员只携带存在性，没有 score 和关联字段。需要排名用 Sorted Set，需要成员属性用 Hash/数据库。</p><h2 id="_7-sorted-set-score-排序和范围索引" tabindex="-1">7. Sorted Set：score 排序和范围索引 <a class="header-anchor" href="#_7-sorted-set-score-排序和范围索引" aria-label="Permalink to &quot;7. Sorted Set：score 排序和范围索引&quot;">​</a></h2><p>Sorted Set 的 member 唯一，每个 member 有双精度 score；按 score 排序，相同 score 再按 member 字典序确定顺序。常用于排行榜、时间索引、延迟队列候选集合。</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ZADD leaderboard:weekly 9830 user:u_9 9750 user:u_2</span></span>
<span class="line"><span>ZREVRANGE leaderboard:weekly 0 9 WITHSCORES</span></span>
<span class="line"><span>ZADD delayed:email 1784246400000 job_55</span></span>
<span class="line"><span>ZRANGEBYSCORE delayed:email -inf 1784246400000 LIMIT 0 100</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>浮点 score 不适合精确货币累计。毫秒时间戳在当前范围内可精确表示整数，但要确认长期和复合编码边界。多个 worker 读取到期任务后还需原子领取，不能 <code>ZRANGE</code> 后独立 <code>ZREM</code> 假定只有一个成功处理。</p><p>排行榜更新和读取很快，但分数权威规则、反作弊和持久历史仍应在受控系统。只在 Redis 中维护且无可重建事件时，故障可能永久丢失排名。</p><h2 id="_8-bitmap-string-上的位操作" tabindex="-1">8. Bitmap：String 上的位操作 <a class="header-anchor" href="#_8-bitmap-string-上的位操作" aria-label="Permalink to &quot;8. Bitmap：String 上的位操作&quot;">​</a></h2><p>Bitmap 不是独立值类型，而是对 String 的 bit 访问。偏移从 0 开始；访问很大偏移会扩展字符串到对应位置，稀疏超大 ID 会浪费内存。</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>SETBIT active:2026-07-17 42 1</span></span>
<span class="line"><span>GETBIT active:2026-07-17 42</span></span>
<span class="line"><span>BITCOUNT active:2026-07-17</span></span>
<span class="line"><span>BITOP AND active:two-days active:2026-07-16 active:2026-07-17</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>适合把稠密整数 ID 映射为每日活跃布尔值。若用户 ID 是 UUID，应先维护稳定紧凑映射；映射本身要持久。<code>BITCOUNT</code> 是精确计数，扫描成本取决于字符串范围，可用 byte 范围限制。</p><h2 id="_9-hyperloglog-近似基数" tabindex="-1">9. HyperLogLog：近似基数 <a class="header-anchor" href="#_9-hyperloglog-近似基数" aria-label="Permalink to &quot;9. HyperLogLog：近似基数&quot;">​</a></h2><p>HyperLogLog 用固定量级内存估算不同元素数量。<code>PFADD</code> 添加，<code>PFCOUNT</code> 估算，<code>PFMERGE</code> 合并。误差是算法性质，不能用于计费、法定人数或精确库存。</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>PFADD uv:2026-07-17 user:u_1 user:u_2 user:u_1</span></span>
<span class="line"><span>PFCOUNT uv:2026-07-17</span></span>
<span class="line"><span>PFMERGE uv:week uv:2026-07-17 uv:2026-07-18</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>适合看板 UV、监控趋势和实验早期估算。验收应声明误差预算，并用小比例精确集合定期比较。HyperLogLog 无法列出添加过的成员，也不能删除单个成员。</p><h2 id="_10-stream-追加日志与消费组" tabindex="-1">10. Stream：追加日志与消费组 <a class="header-anchor" href="#_10-stream-追加日志与消费组" aria-label="Permalink to &quot;10. Stream：追加日志与消费组&quot;">​</a></h2><p>Stream entry 有单调有序 ID 和 field-value 列表。<code>XADD key *</code> 自动生成 ID；<code>XRANGE</code> 回放；<code>XREAD</code> 多读者各自读取；<code>XREADGROUP</code> 让组内消费者分工并把已投递未确认项放入 Pending Entries List（PEL）。</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>XADD order-events MAXLEN ~ 100000 * type order.paid order_id o_9 version 3</span></span>
<span class="line"><span>XGROUP CREATE order-events search-indexer 0 MKSTREAM</span></span>
<span class="line"><span>XREADGROUP GROUP search-indexer worker-1 COUNT 10 BLOCK 5000 STREAMS order-events &gt;</span></span>
<span class="line"><span>XACK order-events search-indexer 1784246400000-0</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p><code>&gt;</code> 只读取从未投递给该组的新消息；恢复自己 pending 项需要使用相应 ID 范围。消费者永久失联时用 <code>XPENDING</code> 观察、<code>XAUTOCLAIM</code>/<code>XCLAIM</code> 转移。确认前完成业务写且业务写幂等；否则 ack 后崩溃会丢处理，处理后 ack 前崩溃会重复。</p><p>Stream 裁剪是近似/精确两种策略，删除 entry 与 consumer-group 引用在新版本中有更细控制。异步复制和默认持久化并不提供 Kafka 风格的独立副本确认语义；对不可丢事件要评估 AOF fsync、复制、failover 窗口和 <code>WAIT</code> 的有限保证。</p><h2 id="_11-geo-经纬度成员索引" tabindex="-1">11. Geo：经纬度成员索引 <a class="header-anchor" href="#_11-geo-经纬度成员索引" aria-label="Permalink to &quot;11. Geo：经纬度成员索引&quot;">​</a></h2><p>Geo 命令底层使用 Sorted Set 编码位置，支持添加坐标和按半径/边界查询。经度在前、纬度在后：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GEOADD stores 116.397389 39.908722 store:beijing</span></span>
<span class="line"><span>GEOSEARCH stores FROMLONLAT 116.4 39.9 BYRADIUS 5 km WITHDIST ASC COUNT 20</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>适合附近门店候选，不替代专业 GIS 的复杂多边形、道路距离、坐标系转换。输入必须验证范围和采用的坐标系；中国业务常见 GCJ-02 与 WGS84 混用会产生位置偏差。Redis Geo 结果是几何距离候选，实际配送范围还需道路/行政规则。</p><h2 id="_12-多命令原子性-事务、lua-与-functions" tabindex="-1">12. 多命令原子性：事务、Lua 与 Functions <a class="header-anchor" href="#_12-多命令原子性-事务、lua-与-functions" aria-label="Permalink to &quot;12. 多命令原子性：事务、Lua 与 Functions&quot;">​</a></h2><p><code>MULTI</code>/<code>EXEC</code> 将排队命令按顺序执行，中间不会插入其他客户端命令；它没有关系数据库式自动回滚。排队时语法错误可能使 EXEC 拒绝，运行时某条命令错误不会回滚其他已执行命令。</p><p><code>WATCH</code> 提供乐观检查：被监视 key 在 EXEC 前改变则事务失败，客户端重新读取并重试。高争用下重试成本上升。</p><p>Lua/Redis Functions 在服务端原子执行，适合检查后修改多个 key。脚本必须有界，长脚本会阻塞其他命令；Cluster 中所有访问 key 必须满足 slot 规则并显式声明。脚本返回前不能调用外部服务。</p><h2 id="_13-cluster、hash-slot-与-key-设计" tabindex="-1">13. Cluster、hash slot 与 key 设计 <a class="header-anchor" href="#_13-cluster、hash-slot-与-key-设计" aria-label="Permalink to &quot;13. Cluster、hash slot 与 key 设计&quot;">​</a></h2><p>Redis Cluster 将 key 映射到 16384 个 slot。多 key 命令通常要求 key 在同一 slot；<code>{...}</code> hash tag 让花括号内部分参与 slot 计算：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>cart:{tenant7:user9}:items</span></span>
<span class="line"><span>cart:{tenant7:user9}:total</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>hash tag 便于原子操作，也可能把一个大租户所有 key 集中到单 slot。只把必须共同操作的最小实体放同 tag。key 名包含环境、业务、租户和实体，但避免 PII；Redis 管理/慢日志可能暴露 key。</p><h2 id="_14-内存、持久化与删除成本" tabindex="-1">14. 内存、持久化与删除成本 <a class="header-anchor" href="#_14-内存、持久化与删除成本" aria-label="Permalink to &quot;14. 内存、持久化与删除成本&quot;">​</a></h2><p>内存不等于值长度：key 对象、编码、allocator 碎片、过期字典、复制/AOF buffer 都占空间。用 <code>MEMORY USAGE</code> 抽样，<code>INFO memory</code> 观察 dataset、RSS、fragmentation 和 <code>mem_not_counted_for_evict</code>。</p><p>大 key 的复制、迁移、RDB fork copy-on-write、删除和网络会形成延迟尖峰。用 <code>UNLINK</code> 把释放内存放后台只能降低主线程释放成本，逻辑删除仍立即发生，后台释放仍耗 CPU/内存带宽。</p><p>RDB 是时间点快照，AOF 记录写命令并可按策略 fsync；两者可组合。具体选择由恢复时间和数据损失预算决定。缓存可从数据库重建时仍要验证冷启动压力，而非简单关闭持久化。</p><h2 id="_15-应用案例一-活动签到分析" tabindex="-1">15. 应用案例一：活动签到分析 <a class="header-anchor" href="#_15-应用案例一-活动签到分析" aria-label="Permalink to &quot;15. 应用案例一：活动签到分析&quot;">​</a></h2><h3 id="输入与约束" tabindex="-1">输入与约束 <a class="header-anchor" href="#输入与约束" aria-label="Permalink to &quot;输入与约束&quot;">​</a></h3><p>每天 3000 万注册用户中约 500 万活跃；需要精确 DAU、近似周 UV、连续两日活跃集合；用户主键是 UUID；结果可从事件重建。</p><h3 id="处理" tabindex="-1">处理 <a class="header-anchor" href="#处理" aria-label="Permalink to &quot;处理&quot;">​</a></h3><ol><li>PostgreSQL 持久维护 UUID → dense integer 的稳定映射。</li><li>每日 Bitmap 按 dense ID <code>SETBIT</code>，用 <code>BITCOUNT</code> 得到精确 DAU。</li><li>同时对 UUID 执行 <code>PFADD</code>，合并七天 key 得近似周 UV。</li><li><code>BITOP AND</code> 生成连续两日活跃，设置 35 天 TTL。</li><li>原始事件进入持久日志，Redis 丢失可按日期重建。</li></ol><h3 id="输出与验证" tabindex="-1">输出与验证 <a class="header-anchor" href="#输出与验证" aria-label="Permalink to &quot;输出与验证&quot;">​</a></h3><p>看板明确 DAU 精确、周 UV 近似。每日从数据仓库抽样对比 HLL 误差；检查 Bitmap 最大 offset 和内存；故障恢复从事件水位重放。</p><h3 id="失败注入" tabindex="-1">失败注入 <a class="header-anchor" href="#失败注入" aria-label="Permalink to &quot;失败注入&quot;">​</a></h3><p>删除一天 Bitmap 后，API 不返回 0 冒充事实，而标记数据 unavailable 并触发重建。若 UUID 直接哈希到 64 位 offset，String 会因巨大稀疏偏移不可用；必须使用 dense mapping。</p><h2 id="_16-应用案例二-搜索索引消费" tabindex="-1">16. 应用案例二：搜索索引消费 <a class="header-anchor" href="#_16-应用案例二-搜索索引消费" aria-label="Permalink to &quot;16. 应用案例二：搜索索引消费&quot;">​</a></h2><h3 id="输入与约束-1" tabindex="-1">输入与约束 <a class="header-anchor" href="#输入与约束-1" aria-label="Permalink to &quot;输入与约束&quot;">​</a></h3><p>订单数据库提交 outbox，投递到 Redis Stream；两个独立组分别更新搜索和发送通知。搜索消费者可重复，通知不得重复发送。</p><h3 id="处理-1" tabindex="-1">处理 <a class="header-anchor" href="#处理-1" aria-label="Permalink to &quot;处理&quot;">​</a></h3><ol><li>outbox publisher 用 event ID <code>XADD</code>，字段含 schema version、aggregate ID 和版本。</li><li>建立 <code>search-indexer</code>、<code>notifier</code> 两个 group；各组独立进度。</li><li>搜索端按订单版本 upsert；旧版本事件不覆盖新文档。</li><li>通知端在数据库以 event ID 唯一约束登记发送意图，再调用供应商。</li><li>成功后 XACK；超时留在 PEL，由健康 worker claim。</li><li>定期观察 pending 数、最老 idle、重复处理率和 stream 长度。</li></ol><h3 id="输出与验证-1" tabindex="-1">输出与验证 <a class="header-anchor" href="#输出与验证-1" aria-label="Permalink to &quot;输出与验证&quot;">​</a></h3><p>同一事件重复投递三次，搜索最终版本正确，通知意图只有一条。停止 worker 后 PEL 增长；恢复后 reclaim 并清空。裁剪策略保留大于最大故障恢复窗口的历史。</p><h3 id="失败注入-1" tabindex="-1">失败注入 <a class="header-anchor" href="#失败注入-1" aria-label="Permalink to &quot;失败注入&quot;">​</a></h3><p>在业务提交后、XACK 前杀进程，事件重投但消费者幂等。若先 ack 后提交，杀进程会永久漏处理；测试必须证明顺序正确。</p><h2 id="_17-方案取舍" tabindex="-1">17. 方案取舍 <a class="header-anchor" href="#_17-方案取舍" aria-label="Permalink to &quot;17. 方案取舍&quot;">​</a></h2><table tabindex="0"><thead><tr><th>需求</th><th>候选</th><th>不应选择的信号</th></tr></thead><tbody><tr><td>简单字节缓存</td><td>String</td><td>频繁局部字段更新且值很大</td></tr><tr><td>扁平对象局部更新</td><td>Hash</td><td>深层结构/复杂查询</td></tr><tr><td>头尾队列</td><td>List</td><td>需要多消费组、重放、DLQ</td></tr><tr><td>唯一成员</td><td>Set</td><td>需要排序或成员属性</td></tr><tr><td>排名/时间候选</td><td>Sorted Set</td><td>精确 decimal 计算</td></tr><tr><td>稠密布尔</td><td>Bitmap</td><td>稀疏巨大 ID</td></tr><tr><td>近似基数</td><td>HLL</td><td>计费/审计需精确</td></tr><tr><td>短期事件协作</td><td>Stream</td><td>明确需要更强持久日志/跨区域保证</td></tr><tr><td>附近候选</td><td>Geo</td><td>道路网络/复杂 GIS</td></tr></tbody></table><h2 id="_18-调试与生产观测" tabindex="-1">18. 调试与生产观测 <a class="header-anchor" href="#_18-调试与生产观测" aria-label="Permalink to &quot;18. 调试与生产观测&quot;">​</a></h2><ul><li><code>INFO commandstats</code>：命令调用、耗时、拒绝。</li><li><code>SLOWLOG</code>：超过阈值的命令；参数可能敏感，访问受控。</li><li><code>LATENCY DOCTOR</code>/latency events：fork、AOF、过期等尖峰。</li><li><code>MEMORY USAGE</code>、<code>--bigkeys</code>/<code>--memkeys</code>：抽样大 key；生产扫描控制速率。</li><li><code>INFO stats</code>：hits/misses、expired、evicted、rejected connections。</li><li>Stream：<code>XINFO GROUPS</code>、<code>XPENDING</code>、lag、最老 pending。</li><li>Cluster：slot 分布、迁移、重定向、单节点 CPU/内存倾斜。</li></ul><p>客户端必须设置连接、命令、池等待 timeout；重试只对幂等操作且有预算。Redis 故障时缓存路径应降级到数据库并限制并发，不能让所有 miss 直接压垮事实源。</p><h2 id="_19-综合练习与验收" tabindex="-1">19. 综合练习与验收 <a class="header-anchor" href="#_19-综合练习与验收" aria-label="Permalink to &quot;19. 综合练习与验收&quot;">​</a></h2><p>实现“实时活动中心”：Hash 缓存活动摘要、Set 记录收藏、Sorted Set 排名、Bitmap 精确日活、HLL 近似周 UV、Stream 驱动异步投影。</p><p>验收标准：</p><ol><li>每种类型有明确访问模式与淘汰/保留策略。</li><li>Cluster 多 key 原子操作使用最小 hash tag，热点可量化。</li><li>Stream 消费者能从 PEL 恢复，重复消息不重复副作用。</li><li>大 key、内存、命中率、eviction、pending 和延迟有告警。</li><li>关闭 Redis 后核心写入仍正确，缓存恢复不会击穿数据库。</li><li>精确与近似指标在 API 和看板中明确区分。</li></ol><h2 id="来源" tabindex="-1">来源 <a class="header-anchor" href="#来源" aria-label="Permalink to &quot;来源&quot;">​</a></h2><ul><li><a href="https://redis.io/docs/latest/operate/oss_and_stack/stack-with-enterprise/release-notes/redisce/" target="_blank" rel="noreferrer">Redis Open Source 8.8 release notes</a>（访问日期：2026-07-17）</li><li><a href="https://redis.io/docs/latest/develop/data-types/" target="_blank" rel="noreferrer">Redis data types</a>（访问日期：2026-07-17）</li><li><a href="https://redis.io/docs/latest/develop/data-types/streams/" target="_blank" rel="noreferrer">Redis Streams</a>（访问日期：2026-07-17）</li><li><a href="https://redis.io/docs/latest/operate/oss_and_stack/reference/cluster-spec/" target="_blank" rel="noreferrer">Redis Cluster specification</a>（访问日期：2026-07-17）</li><li><a href="https://redis.io/docs/latest/operate/oss_and_stack/management/persistence/" target="_blank" rel="noreferrer">Redis persistence</a>（访问日期：2026-07-17）</li></ul>`,90)])])}const b=a(i,[["render",r]]);export{u as __pageData,b as default};
